module mem_srnd(input clk, input [5:0] addr, input rd_en, input rst, output [2:0] data);
reg [2:0] mem [0:61];
always @(posedge clk) begin
  if (rst) data <= 3'b000;
  else if (rd_en) data <= mem[addr];
end
endmodule

module mem_ce_srst(input clk, input [5:0] addr, input rd_en, input ce, input rst, output [2:0] data);
reg [2:0] mem [0:61];
reg [2:0] rdata;
always @(posedge clk) begin
  if (rst && !ce) rdata <= 3'b000;
  else if (rd_en) rdata <= mem[addr];
end
assign data = rdata;
endmodule
